function clean(v) { if (v === null || v === undefined) return null; const s = String(v).trim(); return s === '' ? null : s; }
function num(v) { if (v === null || v === undefined || v === '') return null; const s = String(v).replace('%', '').replace('K', '').replace('M', '').replace(',', '').trim(); const n = Number(s); return Number.isFinite(n) ? n : null; }
function classifySurprise(e) { const actual = num(e.actual); const forecast = num(e.forecast); const usual = String(e.usual_effect || '').toLowerCase(); if (actual === null || forecast === null) return 'pending'; let goodIfHigher = true; if (usual.includes('less than') || usual.includes('lower') || usual.includes('actual less')) goodIfHigher = false; if (actual === forecast) return 'inline'; return (goodIfHigher ? actual > forecast : actual < forecast) ? 'beat' : 'miss'; }
function currencySignal(currency, surprise) { if (surprise === 'beat') return 'BULLISH'; if (surprise === 'miss') return 'BEARISH'; if (surprise === 'inline') return 'NEUTRAL'; return 'PENDING'; }
function impactRank(impact) { const s = String(impact || '').toLowerCase(); if (s.includes('high')) return 3; if (s.includes('medium')) return 2; if (s.includes('low')) return 1; return 0; }
